# 输入获取
m = int(input())
arr = list(map(int, input().split()))


# 算法入口
def getResult(arr, m):
    ans = []
    for i in range(m):
        flag = True
        for j in range(i+1, m):
            if arr[j] > arr[i]:
                flag = False
                ans.append((j-i) * (arr[j] - arr[i]))
                break

        if flag:
            ans.append(arr[i])

    return " ".join(map(str, ans))


# 算法调用
print(getResult(arr, m))
